code.imports:
import { tags } from 'decantr/tags';
import { css } from 'decantr/css';
import { Breadcrumb, Badge, Button, icon } from 'decantr/components';

code.example:
function DetailHeader() {
  const { div, h1 } = tags;
  const title = 'Project Alpha';
  const breadcrumbs = [{ label: 'Home', href: '/' }, { label: 'Projects', href: '/projects' }, { label: 'Project Alpha' }];
  const status = 'active';

  return div({ class: css('_flex _col _gap3 _pb4 _borderB') },
    Breadcrumb({ items: breadcrumbs }),
    div({ class: css('_flex _aic _jcsb') },
      div({ class: css('_flex _aic _gap3') },
        h1({ class: css('_heading3') }, title),
        status ? Badge({ variant: status === 'active' ? 'success' : 'default' }, status) : null
      ),
      div({ class: css('_flex _gap2') },
        Button({ variant: 'outline', size: 'sm' }, icon('edit'), 'Edit'),
        Button({ variant: 'outline', size: 'sm' }, icon('share'), 'Share')
      )
    )
  );
}

code.imports:
import { tags } from 'decantr/tags';
import { css } from 'decantr/css';
import { Avatar, Button, icon } from 'decantr/components';

code.example:
function ProfileHeader({ user }) {
  const { div, h2, p, span, img } = tags;

  return div({ class: css('_flex _col') },
    div({ class: css('_relative _wfull _h[200px] _overflow[hidden] _r4') },
      img({ src: user.banner, alt: 'Banner', class: css('_wfull _hfull _object[cover]') })
    ),
    div({ class: css('_flex _aic _jcsb _px6 _mt[-40px]') },
      div({ class: css('_flex _aic _gap4') },
        Avatar({ src: user.avatar, size: 'xl', class: css('_b[3px_solid_var(--d-bg)]') }),
        div({ class: css('_flex _col _gap1 _mt[40px]') },
          h2({ class: css('_heading3') }, user.name),
          p({ class: css('_fgmuted') }, user.bio),
          div({ class: css('_flex _aic _gap4 _textsm _fgmuted') },
            user.location ? span({}, icon('map-pin'), ` ${user.location}`) : null,
            user.website ? span({}, icon('link'), ` ${user.website}`) : null
          )
        )
      ),
      Button({ variant: 'outline', class: css('_mt[40px]') }, icon('edit'), 'Edit Profile')
    )
  );
}

